def build_siwe_like_message(address: str, nonce: str, issued_at: Optional[int] = None) -> str:
    address = _normalize_address(address)
    issued_at = issued_at or _now()
    issued_iso = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(issued_at))
    msg = (
        f"{DOMAIN} wants you to sign in with your Ethereum account:\n"
        f"{address}\n\n"
        f"Sign in to {APP_NAME}.\n\n"
        f"URI: https://{DOMAIN}\n"
        f"Version: 1\n"
        f"Chain ID: {CHAIN_ID}\n"
        f"Nonce: {nonce}\n"
        f"Issued At: {issued_iso}"
    )
    return msg


def recover_address_from_signature(message: str, signature: str) -> str:
    try:
        msg = encode_defunct(text=message)
        recovered = Web3().eth.account.recover_message(msg, signature=signature)
        return _normalize_address(recovered)
    except Exception as e:
        raise ValueError(f"Signature recovery failed: {str(e)}")


